def fibonacci(n):
    if n <= 0:
        raise ValueError("n must be a positive integer")
    if n == 1:
        return 0
    if n == 2:
        return 1
    a, b = 0, 1
    for _ in range(2, n):
        a, b = b, a + b
    return b

