#!/usr/bin/perl
use strict;
use warnings;

my $filename = $ARGV[0];
die "Usage: $0 <filename>\n" unless defined $filename;
open(my $fh, '<', $filename) or die "Cannot open file '$filename': $!\n";

my %freq;
while (my $line = <$fh>) {
    chomp $line;
    my @words = split /\s+/, $line;
    for my $word (@words) {
        next if $word eq '';
        $word = lc($word);
        $freq{$word}++;
    }
}
close($fh);

my @sorted = sort { $freq{$b} <=> $freq{$a} || $a cmp $b } keys %freq;

my $count = 0;
for my $word (@sorted) {
    last if $count >= 3;
    print "$word: $freq{$word}\n";
    $count++;
}

#!/usr/bin/perl
use strict;
use warnings;

my $filename = $ARGV[0];

open(my $fh, '<', $filename) or die "Cannot open file '$filename': $!";

while (my $line = <$fh>) {
    chomp $line;
    my @fields = split(/,/, $line);
    if (defined $fields[1] && $fields[1] =~ /^\d+$/ && $fields[1] > 30) {
        print "$line\n";
    }
}

close($fh);

